import { useNavigate } from "react-router-dom";
import photo from "../Files/discord server icon.gif"

function MiniUser() {
  const navigate = useNavigate()
  return (
    <div className="mini-user" onClick={()=>navigate("/settings")}>
      <img src={photo} alt="" />
    </div>
  );
}

export default MiniUser;
